pure fn sort_words(s: Text) -> Text {
    words = split(s, " ")
    sorted_words = sort(words)
    return join(sorted_words, " ")
}

entry main(x: Text) { return sort_words("banana cherry apple date") }

pure fn is_even(n: Number) -> Boolean {
    return n % 2 == 0
}

pure fn sum_even_numbers(start: Number, end: Number) -> Number {
    total = 0
    for i in range(start, end + 1) {
        if is_even(i) { total = total + i }
    }
    return total
}

entry main(x: Text) { return sum_even_numbers(1, 100) }

pure fn fahrenheit_to_celsius(f: Number) -> Number {
