pure fn is_longer_than_three(word: Text) -> Boolean {
    return length(word) > 3
}

pure fn count_long_words(sentence: Text) -> Number {
    words = split(sentence, " ")
    count = 0
    for word in words {
        if is_longer_than_three(word) {
            count = count + 1
        }
    }
    return count
}

entry main(x: Text) {
    sentence = "the quick brown fox jumps over the lazy dog"
    return count_long_words(sentence)
}

fn fizzbuzz(n: Number) -> Text {
    if n % 15 == 0 { return "FizzBuzz" }
    if n % 3 == 0 { return "Fizz" }
    if n % 5 == 0 { return "Buzz" }
    return to_text(n)
}

fn fizzbuzz_range(start: Number, end: Number) -> Text {
    results = []
    for i in range(start, end + 1) {
        results = append(results, fizzbuzz(i))
    }
    return join(results, ", ")
}

entry main() {
