pure fn remove_duplicates(lst: [Number]) -> [Number] {
    seen = set()
    result = []
    for item in lst {
        if item not in seen {
            seen = append(seen, item)
            result = append(result, item)
        }
    }
    return result
}

entry main(x: Text) { return remove_duplicates([1, 3, 2, 3, 1, 4, 2, 5]) }

pure fn count_chars(s: Text) -> {char: Number} {
    counts = {}
    for c in split(lower(s), "") {
        if has_key(counts, c) {
            counts[c] = counts[c] + 1
        } else {
            counts[c] = 1
        }
    }
    return counts
}

entry main(x: Text) { return count_chars("mississippi") }

fn fibonacci(n: Number) -> [Number] {
    if n <= 0 { return [] }
    if n == 1 { return [0] }
    if n == 2 { return [0, 1] }
    fibs = [0, 1]
    for i in range(2, n) {
        next = fibs[i - 1] + fibs[i - 2]
        fibs = append(fibs, next)
    }
    return fibs
}

entry main(x: Text) {
    return fibonacci(10)
}

