fn parse_csv(csv_text: Text) -> [Record] {
    lines = split(trim(csv_text), "\n")
    headers = split(lines[0], ",")
    records = []
    for line in lines[1:] {
        fields = split(line, ",")
        record = {}
        for i in range(length(headers)) {
            record[headers[i]] = fields[i]
        }
        records = append(records, record)
    }
    return records
}

