import parse_date from "stdlib/utils"

fn parse_dates(text: Text) -> [Text, Text] {
    dates = split(text, ", ")
    return [trim(dates[0].split(": ")[1]), trim(dates[1].split(": ")[1])]
}

fn days_between(date1: Text, date2: Text) -> Number {
    date1 = parse_date(date1)
    date2 = parse_date(date2)
    return abs(date2 - date1)
}

fn is_reasonable_timeline(days: Number) -> Text {
    if days >= 30 { return "Reasonable" }
    return "Unreasonable"
}

entry main(text: Text) {
    [meeting_date, deadline_date] = parse_dates(text)
    days = days_between(meeting_date, deadline_date)
    return join([to_text(days), " days between meeting and deadline. Timeline is ", is_reasonable_timeline(days)], "")
}

