pure fn percentile(value: Number, sorted_list: [Number]) -> Number {
    n = length(sorted_list)
    rank = 0
    for num in sorted_list {
        if num >= value { rank = rank + 1 }
    }
    return (rank / n) * 100
}

entry main(numbers: Text) {
    numbers_list = map(split(numbers, ", "), to_number)
    sorted_numbers = sort_desc(numbers_list)
    value = 42
    percentile_value = percentile(value, sorted_numbers)
    return join([to_text(sorted_numbers), "\n", to_text(value), " falls in the ", to_text(percentile_value), "th percentile"], "")
}

