import stdlib.utils as utils

fn mean(numbers: [Number]) -> Number {
    return sum_list(numbers) / length(numbers)
}

fn variance(numbers: [Number]) -> Number {
    avg = mean(numbers)
    sum_diff_squared = 0
    for num in numbers {
        sum_diff_squared = sum_diff_squared + pow(num - avg, 2)
    }
    return sum_diff_squared / length(numbers)
}

fn standard_deviation(numbers: [Number]) -> Number {
    return sqrt(variance(numbers))
}

entry main(numbers: Text) {
    nums = to_number(split(numbers, ", "))
    std_dev = standard_deviation(nums)
    return join([to_text(std_dev), " — This data is ", if std_dev > 5 then "highly variable" else "not highly variable"], "")
}

pure fn reverse_word(word: Text) -> Text {
    return join(split(word, ""), reverse=True)
}

pure fn reverse_words(sentence: Text) -> Text {
    words = split(sentence, " ")
    reversed_words = map(words, reverse_word)
    return join(reversed_words, " ")
}

