import extract from "stdlib/utils"

fn is_valid_email(email: Text) -> Boolean {
    return starts_with(email, "a-z0-9._%+-") and ends_with(email, "a-z0-9._%+-@a-z0-9.-.a-z")
}

fn draft_greeting(name: Text) -> Text {
    return join(["Hello ", name, "!"])
}

entry main(text: Text) {
    emails = extract(text, "email")
    valid_emails = filter(emails, is_valid_email)
    greetings = map(valid_emails, draft_greeting)
    return join(greetings, "\n")
}

import math from "stdlib/core"

fn compound_interest(principal: Number, rate: Number, years: Number) -> Number {
    return principal * math.pow(1 + rate / 100, years)
}

intent explain_compound_interest(principal: Number, rate: Number, years: Number) -> Text {
    goal: explain_compound_interest_to_teenager
}

entry main(principal: Text, rate: Text, years: Text) {
    principal = to_number(principal)
    rate = to_number(rate)
    years = to_number(years)

    interest = compound_interest(principal, rate, years)
    explanation = explain_compound_interest(principal, rate, years)

    return join(["The compound interest on $", to_text(principal), " at ", to_text(rate), "% for ", to_text(years), " years is $", to_text(interest), ".", explanation], " ")
}

import classify from "stdlib/language"

pure fn count_lines(text: Text) -> Number {
    return length(split(text, "\n"))
}

pure fn count_words(text: Text) -> Number {
    return length(split(text, " "))
}

pure fn count_chars(text: Text) -> Number {
    return length(text)
}

intent rate_writing(text: Text) -> Text {
    goal: concise_or_verbose
}

entry main(text: Text) {
    lines = count_lines(text)
    words = count_words(text)
    chars = count_chars(text)
    rating = rate_writing(text)
    return join([to_text(lines), " lines, ", to_text(words), " words, ", to_text(chars), " characters. ", rating], "")
}

pure fn parse_cities(text: Text) -> [[Text, Number]] {
    pairs = split(text, ",")
    result = []
    for pair in pairs {
        city, lat = split(pair, ":")
        result = append(result, [city, to_number(lat)])
    }
    return result
}

pure fn sort_by_lat(cities: [[Text, Number]]) -> [[Text, Number]] {
    return sort(cities, "by_second")
}

intent describe_pattern(cities: [[Text, Number]]) -> Text {
    goal: describe_geographic_pattern
}

entry main(input: Text) {
    cities = parse_cities(input)
    sorted_cities = sort_by_lat(cities)
    pattern = describe_pattern(sorted_cities)
    return pattern
}

fn fibonacci(n: Number) -> Number {
    if n <= 1 { return n }
    return fibonacci(n - 1) + fibonacci(n - 2)
}

fn fibonacci_sequence(limit: Number) -> [Number] {
    sequence = []
    for i in range(0, limit) {
        sequence = append(sequence, fibonacci(i))
    }
    return sequence
}

entry main(limit: Text) {
    sequence = fibonacci_sequence(to_number(limit))
    return join(map(sequence, to_text), ", ")
}

